// Always use try-with-resources (Java 7+)
try (BufferedReader reader = new BufferedReader(
        new FileReader("data.txt"))) {
    String line;
    while ((line = reader.readLine()) != null) {
        process(line);
    }
} // reader.close() called automatically — even on exception

// Modern file reading (Java 11+)
String content = Files.readString(Path.of("data.txt"));
List<String> lines = Files.readAllLines(Path.of("data.txt"));

// Streaming large files (memory-efficient)
try (Stream<String> lines = Files.lines(Path.of("large.txt"))) {
    lines.filter(l -> l.contains("ERROR"))
         .forEach(System.out::println);
}

// Path operations
Path path = Path.of("/home/user/docs/file.txt");
path.getFileName();      // file.txt
path.getParent();        // /home/user/docs
path.resolve("other.txt"); // /home/user/docs/other.txt
path.relativize(Path.of("/home/user")); // ../

// File operations with Files utility
String content = Files.readString(path);         // read entire file
List<String> lines = Files.readAllLines(path);   // read all lines
Files.writeString(path, "data", StandardOpenOption.APPEND); // append
Files.copy(src, dest, StandardCopyOption.REPLACE_EXISTING);
Files.move(src, dest, StandardCopyOption.ATOMIC_MOVE);
Files.delete(path);  // throws if not exists
Files.deleteIfExists(path); // no exception

// Walking directory trees (lazy stream!)
try (Stream<Path> tree = Files.walk(Path.of("/project"))) {
    List<Path> javaFiles = tree
        .filter(p -> p.toString().endsWith(".java"))
        .toList();
}

// Files.find() — walk with filter built-in
try (Stream<Path> found = Files.find(Path.of("/logs"), 5,
        (path, attrs) -> attrs.size() > 1_000_000)) { // files > 1MB
    found.forEach(System.out::println);
}

// WatchService — monitor directory for changes
WatchService watcher = FileSystems.getDefault().newWatchService();
Path.of("/config").register(watcher,
    StandardWatchEventKinds.ENTRY_MODIFY,
    StandardWatchEventKinds.ENTRY_CREATE);

while (true) {
    WatchKey key = watcher.take(); // blocks until event
    for (WatchEvent<?> event : key.pollEvents()) {
        System.out.println(event.kind() + ": " + event.context());
    }
    key.reset(); // ready for next events
}

