// Define a custom annotation
@Retention(RetentionPolicy.RUNTIME)
@Target(ElementType.METHOD)
public @interface Timed {
    String label() default "";
}

// Use it
public class OrderService {
    @Timed(label = "order-processing")
    public void processOrder(Order order) { ... }
}

// Process at runtime via reflection
for (Method method : clazz.getDeclaredMethods()) {
    if (method.isAnnotationPresent(Timed.class)) {
        Timed timed = method.getAnnotation(Timed.class);
        System.out.println("Timed method: " + method.getName()
            + " label=" + timed.label());
    }
}

// Interface
interface UserService {
    User findById(int id);
}

// InvocationHandler — intercepts all calls
InvocationHandler handler = (proxy, method, args) -> {
    long start = System.nanoTime();
    Object result = realService.findById((int) args[0]);
    long elapsed = System.nanoTime() - start;
    System.out.println(method.getName() + " took " + elapsed + "ns");
    return result;
};

// Create proxy instance
UserService proxy = (UserService) Proxy.newProxyInstance(
    UserService.class.getClassLoader(),
    new Class<?>[] { UserService.class },
    handler
);

// Calls go through the handler
User user = proxy.findById(1); // intercepted + timed!

