// Reflection — access check on every call
Method method = MyClass.class.getDeclaredMethod("compute", int.class);
method.setAccessible(true);
Object result = method.invoke(instance, 42); // slow per call

// MethodHandle — access check once, fast invocation
MethodHandles.Lookup lookup = MethodHandles.lookup();
MethodHandle mh = lookup.findVirtual(
    MyClass.class, "compute",
    MethodType.methodType(int.class, int.class));
int result = (int) mh.invoke(instance, 42); // JIT-optimizable!

// VarHandle — modern alternative to Field reflection (Java 9+)
VarHandle vh = MethodHandles.lookup().findVarHandle(
    MyClass.class, "count", int.class);
vh.set(instance, 42);                // set field
int val = (int) vh.get(instance);    // get field
vh.compareAndSet(instance, 42, 43); // atomic CAS!

// Create a reusable HttpClient
HttpClient client = HttpClient.newBuilder()
    .version(HttpClient.Version.HTTP_2)
    .connectTimeout(Duration.ofSeconds(10))
    .followRedirects(HttpClient.Redirect.NORMAL)
    .build();

// Synchronous GET
HttpRequest request = HttpRequest.newBuilder()
    .uri(URI.create("https://api.example.com/users"))
    .header("Accept", "application/json")
    .GET()
    .build();

HttpResponse<String> response = client.send(
    request, HttpResponse.BodyHandlers.ofString());
System.out.println(response.statusCode()); // 200
System.out.println(response.body());       // JSON string

// Asynchronous GET
CompletableFuture<HttpResponse<String>> asyncResponse = 
    client.sendAsync(request, HttpResponse.BodyHandlers.ofString());
asyncResponse
    .thenApply(HttpResponse::body)
    .thenAccept(System.out::println);

// POST with JSON body
HttpRequest postReq = HttpRequest.newBuilder()
    .uri(URI.create("https://api.example.com/users"))
    .header("Content-Type", "application/json")
    .POST(HttpRequest.BodyPublishers.ofString(
        "{\"name\": \"Alice\", \"email\": \"alice@example.com\"}"))
    .build();
